using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.MSBuild;
using Microsoft.Build.Locator;
using System.Diagnostics;

namespace BuildValidator;


public enum BuildStatus
{
    Success,
    Failed,
    Skipped
}

public record BuildResult
{
    public string ProjectPath { get; init; } = string.Empty;
    public string ProjectName { get; init; } = string.Empty;
    public BuildStatus Status { get; init; }
    public TimeSpan Duration { get; init; }
    public List<BuildDiagnostic> Diagnostics { get; init; } = new();
    public string? ErrorMessage { get; init; }
    public List<CodeAnalysisResult>? AnalysisResults { get; init; }
}

public record BuildDiagnostic
{
    public DiagnosticSeverity Severity { get; init; }
    public string Id { get; init; } = string.Empty;
    public string Message { get; init; } = string.Empty;
    public string? FilePath { get; init; }
    public int LineNumber { get; init; }
    public int ColumnNumber { get; init; }
}

public class BuildEngine
{
    private readonly CommandLineOptions _options;

    public BuildEngine(CommandLineOptions options)
    {
        _options = options;
    }

    public async Task<BuildResult> CompileProjectAsync(string projectPath)
    {
        var stopwatch = Stopwatch.StartNew();
        var projectName = Path.GetFileNameWithoutExtension(projectPath);

        // Handle metrics-only mode - skip MSBuild compilation
        if (_options.MetricsOnly)
        {
            return await AnalyzeProjectMetricsOnly(projectPath, projectName, stopwatch);
        }

        try
        {
            // Use MSBuildWorkspace for full Roslyn analysis
            using var workspace = MSBuildWorkspace.Create(new Dictionary<string, string>
            {
                ["Configuration"] = _options.Configuration
            });

            // Load the project
            var project = await workspace.OpenProjectAsync(projectPath);
            var compilation = await project.GetCompilationAsync();

            stopwatch.Stop();

            if (compilation == null)
            {
                return new BuildResult
                {
                    ProjectPath = projectPath,
                    ProjectName = projectName,
                    Status = BuildStatus.Failed,
                    Duration = stopwatch.Elapsed,
                    ErrorMessage = "Failed to create compilation"
                };
            }

            // Check for compilation errors
            var diagnostics = ConvertDiagnostics(compilation.GetDiagnostics());
            var hasErrors = diagnostics.Any(d => d.Severity == DiagnosticSeverity.Error);
            var status = hasErrors ? BuildStatus.Failed : BuildStatus.Success;

            // Perform code analysis if requested
            List<CodeAnalysisResult>? analysisResults = null;
            if (_options.EnableAnalysis || _options.IncludeMetrics || _options.MetricsOnly)
            {
                analysisResults = await PerformCodeAnalysis(project);
            }

            return new BuildResult
            {
                ProjectPath = projectPath,
                ProjectName = projectName,
                Status = status,
                Duration = stopwatch.Elapsed,
                Diagnostics = diagnostics,
                AnalysisResults = analysisResults
            };
        }
        catch (Exception ex)
        {
            stopwatch.Stop();
            return new BuildResult
            {
                ProjectPath = projectPath,
                ProjectName = projectName,
                Status = BuildStatus.Failed,
                Duration = stopwatch.Elapsed,
                ErrorMessage = ex.Message
            };
        }
    }



    private List<BuildDiagnostic> ConvertDiagnostics(IEnumerable<Diagnostic> diagnostics)
    {
        var result = new List<BuildDiagnostic>();

        foreach (var diagnostic in diagnostics)
        {
            // Skip hidden diagnostics unless verbose
            if (diagnostic.Severity == DiagnosticSeverity.Hidden && _options.Verbosity != "detailed")
                continue;

            // Skip informational diagnostics unless verbose
            if (diagnostic.Severity == DiagnosticSeverity.Info && _options.Verbosity == "minimal")
                continue;

            // Skip warnings unless requested
            if (diagnostic.Severity == DiagnosticSeverity.Warning && !_options.IncludeWarnings)
                continue;

            var location = diagnostic.Location;
            var lineSpan = location.GetLineSpan();

            result.Add(new BuildDiagnostic
            {
                Severity = diagnostic.Severity,
                Id = diagnostic.Id,
                Message = diagnostic.GetMessage(),
                FilePath = location.IsInSource ? location.SourceTree?.FilePath : null,
                LineNumber = location.IsInSource ? lineSpan.StartLinePosition.Line + 1 : 0,
                ColumnNumber = location.IsInSource ? lineSpan.StartLinePosition.Character + 1 : 0
            });
        }

        return result;
    }

    public async Task<BuildResult> CompileSolutionAsync(string solutionPath)
    {
        var stopwatch = Stopwatch.StartNew();
        var solutionName = Path.GetFileNameWithoutExtension(solutionPath);

        try
        {
            // Use MSBuildWorkspace to load the entire solution
            using var workspace = MSBuildWorkspace.Create(new Dictionary<string, string>
            {
                ["Configuration"] = _options.Configuration
            });

            // Load the solution
            var solution = await workspace.OpenSolutionAsync(solutionPath);
            var allDiagnostics = new List<BuildDiagnostic>();
            var allAnalysisResults = new List<CodeAnalysisResult>();
            var hasErrors = false;

            // Compile all projects in the solution
            foreach (var project in solution.Projects)
            {
                var compilation = await project.GetCompilationAsync();
                if (compilation == null)
                {
                    hasErrors = true;
                    continue;
                }

                // Collect diagnostics from this project
                var diagnostics = ConvertDiagnostics(compilation.GetDiagnostics());
                allDiagnostics.AddRange(diagnostics);
                hasErrors |= diagnostics.Any(d => d.Severity == DiagnosticSeverity.Error);

                // Perform code analysis if requested
                if (_options.EnableAnalysis || _options.IncludeMetrics || _options.MetricsOnly)
                {
                    var projectAnalysis = await PerformCodeAnalysis(project);
                    allAnalysisResults.AddRange(projectAnalysis);
                }
            }

            stopwatch.Stop();

            var status = hasErrors ? BuildStatus.Failed : BuildStatus.Success;

            return new BuildResult
            {
                ProjectPath = solutionPath,
                ProjectName = solutionName,
                Status = status,
                Duration = stopwatch.Elapsed,
                Diagnostics = allDiagnostics,
                AnalysisResults = allAnalysisResults.Any() ? allAnalysisResults : null
            };
        }
        catch (Exception ex)
        {
            stopwatch.Stop();
            return new BuildResult
            {
                ProjectPath = solutionPath,
                ProjectName = solutionName,
                Status = BuildStatus.Failed,
                Duration = stopwatch.Elapsed,
                ErrorMessage = ex.Message
            };
        }
    }

    public async Task<List<BuildResult>> CompileProjectsAsync(IEnumerable<string> projectPaths)
    {
        var results = new List<BuildResult>();

        // For now, build sequentially (we'll add parallel support later)
        foreach (var projectPath in projectPaths)
        {
            var result = await CompileProjectAsync(projectPath);
            results.Add(result);
        }

        return results;
    }

    private async Task<List<CodeAnalysisResult>> PerformCodeAnalysis(Microsoft.CodeAnalysis.Project project)
    {
        var analyzer = new RoslynAnalyzer();
        var analysisResults = new List<CodeAnalysisResult>();

        foreach (var document in project.Documents)
        {
            if (document.FilePath != null && document.FilePath.EndsWith(".cs"))
            {
                try
                {
                    var sourceText = await document.GetTextAsync();
                    var sourceCode = sourceText.ToString();

                    var analysis = await analyzer.AnalyzeCodeAsync(sourceCode, document.FilePath);
                    analysisResults.Add(analysis);
                }
                catch (Exception ex)
                {
                    // Log analysis failure but continue with other files
                    if (_options.Verbosity == "detailed")
                    {
                        Console.WriteLine($"  Warning: Failed to analyze {document.Name}: {ex.Message}");
                    }
                }
            }
        }

        return analysisResults;
    }

    private async Task<BuildResult> AnalyzeProjectMetricsOnly(string projectPath, string projectName, Stopwatch stopwatch)
    {
        try
        {
            var analyzer = new RoslynAnalyzer();
            var analysisResults = new List<CodeAnalysisResult>();

            // Find all .cs files in the project directory
            var projectDir = Path.GetDirectoryName(projectPath);
            if (projectDir != null)
            {
                var csFiles = Directory.GetFiles(projectDir, "*.cs", SearchOption.AllDirectories)
                    .Where(f => !f.Contains("bin") && !f.Contains("obj")) // Skip build output
                    .ToList();

                foreach (var csFile in csFiles)
                {
                    try
                    {
                        var analysis = await analyzer.AnalyzeFileAsync(csFile);
                        analysisResults.Add(analysis);
                    }
                    catch (Exception ex)
                    {
                        if (_options.Verbosity == "detailed")
                        {
                            Console.WriteLine($"  Warning: Failed to analyze {Path.GetFileName(csFile)}: {ex.Message}");
                        }
                    }
                }
            }

            stopwatch.Stop();

            return new BuildResult
            {
                ProjectPath = projectPath,
                ProjectName = projectName,
                Status = BuildStatus.Success,
                Duration = stopwatch.Elapsed,
                Diagnostics = new List<BuildDiagnostic>(),
                AnalysisResults = analysisResults
            };
        }
        catch (Exception ex)
        {
            stopwatch.Stop();
            return new BuildResult
            {
                ProjectPath = projectPath,
                ProjectName = projectName,
                Status = BuildStatus.Failed,
                Duration = stopwatch.Elapsed,
                ErrorMessage = ex.Message,
                AnalysisResults = new List<CodeAnalysisResult>()
            };
        }
    }
}

using Microsoft.CodeAnalysis;

namespace BuildValidator;

public static class BuildResultFormatter
{
    public static void DisplayResults(IEnumerable<BuildResult> results, CommandLineOptions options)
    {
        var resultsList = results.ToList();
        var totalDuration = TimeSpan.FromMilliseconds(resultsList.Sum(r => r.Duration.TotalMilliseconds));
        var successCount = resultsList.Count(r => r.Status == BuildStatus.Success);
        var failureCount = resultsList.Count(r => r.Status == BuildStatus.Failed);

        // Display individual results
        for (int i = 0; i < resultsList.Count; i++)
        {
            var result = resultsList[i];
            DisplayProjectResult(result, i + 1, resultsList.Count, options);
        }

        // Display summary
        Console.WriteLine();
        var summaryColor = failureCount > 0 ? ConsoleColor.Red : ConsoleColor.Green;
        Console.ForegroundColor = summaryColor;
        Console.WriteLine($"Results: {successCount} succeeded, {failureCount} failed ({totalDuration.TotalSeconds:F1}s total)");
        Console.ResetColor();
    }

    private static void DisplayProjectResult(BuildResult result, int index, int total, CommandLineOptions options)
    {
        // Format: [1/5] MyApp.Api ...................... ✓ (2.3s)
        var projectDisplay = $"[{index}/{total}] {result.ProjectName}";
        var statusSymbol = result.Status == BuildStatus.Success ? "✓" : "✗";
        var duration = $"({result.Duration.TotalSeconds:F1}s)";

        // Calculate padding for alignment
        var maxWidth = 50; // Adjust as needed
        var paddingLength = Math.Max(1, maxWidth - projectDisplay.Length);
        var padding = new string('.', paddingLength);

        // Color based on status
        Console.ForegroundColor = result.Status == BuildStatus.Success ? ConsoleColor.Green : ConsoleColor.Red;
        Console.WriteLine($"{projectDisplay} {padding} {statusSymbol} {duration}");
        Console.ResetColor();

        // Show error message if present
        if (!string.IsNullOrEmpty(result.ErrorMessage))
        {
            Console.ForegroundColor = ConsoleColor.Red;
            Console.WriteLine($"  Error: {result.ErrorMessage}");
            Console.ResetColor();
        }

        // Show diagnostics
        DisplayDiagnostics(result.Diagnostics, options);

        // Show analysis results if available
        if (result.AnalysisResults != null && result.AnalysisResults.Any())
        {
            if (options.Verbosity != "minimal")
            {
                Console.WriteLine("  📊 Code Analysis Results:");
            }
            DisplayAnalysisResults(result.AnalysisResults, options);
        }
    }

    private static void DisplayDiagnostics(IEnumerable<BuildDiagnostic> diagnostics, CommandLineOptions options)
    {
        foreach (var diagnostic in diagnostics.OrderBy(d => d.Severity).ThenBy(d => d.FilePath).ThenBy(d => d.LineNumber))
        {
            var severity = diagnostic.Severity switch
            {
                DiagnosticSeverity.Error => "Error",
                DiagnosticSeverity.Warning => "Warning",
                DiagnosticSeverity.Info => "Info",
                DiagnosticSeverity.Hidden => "Hidden",
                _ => "Unknown"
            };

            var color = diagnostic.Severity switch
            {
                DiagnosticSeverity.Error => ConsoleColor.Red,
                DiagnosticSeverity.Warning => ConsoleColor.Yellow,
                DiagnosticSeverity.Info => ConsoleColor.Cyan,
                _ => ConsoleColor.Gray
            };

            var location = "";
            if (!string.IsNullOrEmpty(diagnostic.FilePath) && diagnostic.LineNumber > 0)
            {
                var fileName = Path.GetFileName(diagnostic.FilePath);
                location = $" ({fileName}:{diagnostic.LineNumber})";
            }

            Console.ForegroundColor = color;
            Console.WriteLine($"  {severity} {diagnostic.Id}: {diagnostic.Message}{location}");
            Console.ResetColor();
        }
    }

    private static void DisplayAnalysisResults(IEnumerable<CodeAnalysisResult> analysisResults, CommandLineOptions options)
    {
        foreach (var analysis in analysisResults)
        {
            DisplayCodeMetrics(analysis.CodeMetrics, analysis.FilePath, options);

            if (options.Verbosity == "detailed")
            {
                DisplayDetailedAnalysis(analysis, options);
            }
        }
    }

    private static void DisplayCodeMetrics(CodeMetrics metrics, string filePath, CommandLineOptions options)
    {
        var fileName = Path.GetFileName(filePath);
        Console.ForegroundColor = ConsoleColor.Cyan;
        Console.WriteLine($"    {fileName}: Complexity: {metrics.CyclomaticComplexity}, Maintainability: {metrics.MaintainabilityIndex:F0}, Methods: {metrics.MethodCount}");
        Console.ResetColor();

        // Flag high complexity
        if (metrics.CyclomaticComplexity > options.ComplexityThreshold)
        {
            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine($"      ⚠️  High complexity (>{options.ComplexityThreshold})");
            Console.ResetColor();
        }

        // Flag low maintainability
        if (metrics.MaintainabilityIndex < options.MaintainabilityThreshold)
        {
            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine($"      ⚠️  Low maintainability index (<{options.MaintainabilityThreshold})");
            Console.ResetColor();
        }

        // Excellent code quality
        if (metrics.MaintainabilityIndex >= 80 && metrics.CyclomaticComplexity <= options.ComplexityThreshold)
        {
            Console.ForegroundColor = ConsoleColor.Green;
            Console.WriteLine("      ✨ Excellent code quality");
            Console.ResetColor();
        }
    }

    private static void DisplayDetailedAnalysis(CodeAnalysisResult analysis, CommandLineOptions options)
    {
        // Unused usings
        if (analysis.SemanticAnalysis.UnusedUsings.Any())
        {
            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine("    ⚠️  Unused using statements:");
            foreach (var unused in analysis.SemanticAnalysis.UnusedUsings)
            {
                Console.WriteLine($"      - Line {unused.Line}: {unused.Message}");
            }
            Console.ResetColor();
        }

        // Potential null references
        if (analysis.SemanticAnalysis.PotentialNullReferences.Any())
        {
            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine("    ⚠️  Potential null references:");
            foreach (var nullRef in analysis.SemanticAnalysis.PotentialNullReferences)
            {
                Console.WriteLine($"      - Line {nullRef.Line}: {nullRef.Message}");
            }
            Console.ResetColor();
        }

        // Performance analysis
        DisplayPerformanceAnalysis(analysis.PerformanceAnalysis, options);

        // Syntax analysis details
        if (options.Verbosity == "detailed")
        {
            Console.ForegroundColor = ConsoleColor.Gray;
            Console.WriteLine($"    📝 Lines: {analysis.SyntaxAnalysis.CodeLines} code, {analysis.SyntaxAnalysis.CommentLines} comments, {analysis.SyntaxAnalysis.BlankLines} blank");
            Console.WriteLine($"    🏗️  Structure: {analysis.SyntaxAnalysis.ClassNames.Length} classes, {analysis.SyntaxAnalysis.PropertyNames.Length} properties");
            Console.ResetColor();
        }
    }

    private static void DisplayPerformanceAnalysis(PerformanceAnalysis performance, CommandLineOptions options)
    {
        var allIssues = performance.LinqPerformanceIssues
            .Concat(performance.AllocationIssues)
            .Concat(performance.AsyncPerformanceIssues)
            .Concat(performance.StringPerformanceIssues)
            .ToArray();

        if (!allIssues.Any()) return;

        // Summary for normal verbosity
        if (performance.Metrics.TotalPerformanceIssues > 0)
        {
            Console.ForegroundColor = GetPerformanceColor(performance.Metrics.HighSeverityIssues);
            Console.WriteLine($"    ⚡ Performance: {performance.Metrics.TotalPerformanceIssues} issues " +
                            $"(🔴 {performance.Metrics.HighSeverityIssues} high, " +
                            $"🟡 {performance.Metrics.MediumSeverityIssues} medium, " +
                            $"🟢 {performance.Metrics.LowSeverityIssues} low)");
            Console.ResetColor();
        }

        // Detailed analysis for verbose modes
        if (options.Verbosity == "detailed")
        {
            DisplayPerformanceIssuesByCategory("LINQ Performance", performance.LinqPerformanceIssues);
            DisplayPerformanceIssuesByCategory("Memory Allocation", performance.AllocationIssues);
            DisplayPerformanceIssuesByCategory("Async Performance", performance.AsyncPerformanceIssues);
            DisplayPerformanceIssuesByCategory("String Performance", performance.StringPerformanceIssues);
        }
    }

    private static void DisplayPerformanceIssuesByCategory(string category, PerformanceIssue[] issues)
    {
        if (!issues.Any()) return;

        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine($"    ⚡ {category} Issues:");
        Console.ResetColor();

        foreach (var issue in issues.OrderByDescending(i => i.Severity))
        {
            var severityIcon = issue.Severity switch
            {
                PerformanceSeverity.High => "🔴",
                PerformanceSeverity.Medium => "🟡",
                PerformanceSeverity.Low => "🟢",
                _ => "⚪"
            };

            Console.ForegroundColor = GetSeverityColor(issue.Severity);
            Console.WriteLine($"      {severityIcon} Line {issue.Line}: {issue.Message}");

            if (issue.Recommendation != null)
            {
                Console.ForegroundColor = ConsoleColor.Cyan;
                Console.WriteLine($"         💡 {issue.Recommendation}");
            }

            Console.ResetColor();
        }
    }

    private static ConsoleColor GetPerformanceColor(int highSeverityCount)
    {
        return highSeverityCount switch
        {
            0 => ConsoleColor.Green,
            <= 2 => ConsoleColor.Yellow,
            _ => ConsoleColor.Red
        };
    }

    private static ConsoleColor GetSeverityColor(PerformanceSeverity severity)
    {
        return severity switch
        {
            PerformanceSeverity.High => ConsoleColor.Red,
            PerformanceSeverity.Medium => ConsoleColor.Yellow,
            PerformanceSeverity.Low => ConsoleColor.Green,
            _ => ConsoleColor.Gray
        };
    }
}

using Microsoft.CodeAnalysis.MSBuild;
using Microsoft.CodeAnalysis;

namespace BuildValidator;

public static class BuildValidatorApp
{
    public static async Task<int> RunAsync(CommandLineOptions options)
    {
        var modeText = options.MetricsOnly ? "Analyzing" : 
                      (options.EnableAnalysis || options.IncludeMetrics) ? "Building & Analyzing" : "Building";

        Console.WriteLine($"{modeText} C# Projects in: {options.Directory}");
        Console.WriteLine("==========================================");

        try
        {
            // Discover all project and solution files
            var discoveredFiles = DiscoverProjects(options.Directory);

            if (discoveredFiles.Count == 0)
            {
                Console.WriteLine("No C# project or solution files found.");
                return 1;
            }

            // Solution-first approach: prefer solution files over individual projects
            var solutionFiles = discoveredFiles.Where(f => f.EndsWith(".sln", StringComparison.OrdinalIgnoreCase)).ToList();
            var projectFiles = discoveredFiles.Where(f => f.EndsWith(".csproj", StringComparison.OrdinalIgnoreCase) || 
                                                         f.EndsWith(".vbproj", StringComparison.OrdinalIgnoreCase)).ToList();

            var buildEngine = new BuildEngine(options);
            List<BuildResult> results;

            if (solutionFiles.Any())
            {
                // Solution mode: compile entire solution(s)
                if (options.Verbosity != "minimal")
                {
                    Console.WriteLine($"Found {solutionFiles.Count} solution(s) to build:");
                    foreach (var solution in solutionFiles)
                    {
                        Console.WriteLine($"  {Path.GetFileName(solution)}");
                    }
                    Console.WriteLine();
                }

                results = new List<BuildResult>();
                foreach (var solutionPath in solutionFiles)
                {
                    var result = await buildEngine.CompileSolutionAsync(solutionPath);
                    results.Add(result);
                }
            }
            else if (projectFiles.Any())
            {
                // Fallback mode: compile individual projects
                if (options.Verbosity != "minimal")
                {
                    Console.WriteLine($"Found {projectFiles.Count} project(s) to build:");
                    foreach (var project in projectFiles)
                    {
                        Console.WriteLine($"  {Path.GetFileName(project)}");
                    }
                    Console.WriteLine();
                }

                results = await buildEngine.CompileProjectsAsync(projectFiles);
            }
            else
            {
                Console.WriteLine("No valid C# projects or solutions found.");
                return 1;
            }

            // Display or export results
            await OutputFormatters.WriteResultsAsync(results, options);

            // Return exit code based on results
            var hasFailures = results.Any(r => r.Status == BuildStatus.Failed);
            return hasFailures ? 1 : 0;
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"Error: {ex.Message}");
            if (options.Verbosity == "detailed")
            {
                Console.Error.WriteLine($"Stack trace: {ex.StackTrace}");
            }
            return 1;
        }
    }

    private static List<string> DiscoverProjects(string directory)
    {
        var projectFiles = new List<string>();

        // Look for solution files first
        var solutionFiles = Directory.GetFiles(directory, "*.sln", SearchOption.AllDirectories);
        projectFiles.AddRange(solutionFiles);

        // Then look for individual project files
        var csharpProjects = Directory.GetFiles(directory, "*.csproj", SearchOption.AllDirectories);
        projectFiles.AddRange(csharpProjects);

        var vbProjects = Directory.GetFiles(directory, "*.vbproj", SearchOption.AllDirectories);
        projectFiles.AddRange(vbProjects);

        // Sort for consistent ordering
        projectFiles.Sort();

        return projectFiles;
    }
}

using Microsoft.CodeAnalysis;

namespace BuildValidator;

public record CodeAnalysisResult
{
    public required string FilePath { get; init; }
    public required string SourceCode { get; init; }
    public required SyntaxAnalysis SyntaxAnalysis { get; init; }
    public required SemanticAnalysis SemanticAnalysis { get; init; }
    public required CodeMetrics CodeMetrics { get; init; }
    public required CompilationIssue[] CompilationIssues { get; init; }
    public required PerformanceAnalysis PerformanceAnalysis { get; init; }
}

public record SyntaxAnalysis
{
    public required int TotalLines { get; init; }
    public required int CodeLines { get; init; }
    public required int CommentLines { get; init; }
    public required int BlankLines { get; init; }
    public required string[] ClassNames { get; init; }
    public required string[] MethodNames { get; init; }
    public required string[] PropertyNames { get; init; }
    public required string[] NamespaceNames { get; init; }
    public required string[] UsingDirectives { get; init; }
}

public record SemanticAnalysis
{
    public required TypeInfo[] TypeInfos { get; init; }
    public required SymbolInfo[] SymbolInfos { get; init; }
    public required CodeIssue[] UnusedUsings { get; init; }
    public required CodeIssue[] PotentialNullReferences { get; init; }
}

public record TypeInfo
{
    public required string Name { get; init; }
    public required string FullName { get; init; }
    public required string Kind { get; init; }
    public required bool IsPublic { get; init; }
    public required bool IsStatic { get; init; }
    public required bool IsAbstract { get; init; }
}

public record SymbolInfo
{
    public required string Name { get; init; }
    public required string Kind { get; init; }
    public required string Type { get; init; }
    public required bool IsUsed { get; init; }
}

public record CodeMetrics
{
    public required int CyclomaticComplexity { get; init; }
    public required int NestingDepth { get; init; }
    public required int MethodCount { get; init; }
    public required int ClassCount { get; init; }
    public required int PropertyCount { get; init; }
    public required double MaintainabilityIndex { get; init; }
}

public record CompilationIssue
{
    public required string Id { get; init; }
    public required string Title { get; init; }
    public required string Message { get; init; }
    public required DiagnosticSeverity Severity { get; init; }
    public required int Line { get; init; }
    public required int Column { get; init; }
    public required string Category { get; init; }
}

public record CodeIssue
{
    public required string Message { get; init; }
    public required int Line { get; init; }
    public required int Column { get; init; }
    public required string? FilePath { get; init; }
}

public record PerformanceAnalysis
{
    public required PerformanceIssue[] LinqPerformanceIssues { get; init; }
    public required PerformanceIssue[] AllocationIssues { get; init; }
    public required PerformanceIssue[] AsyncPerformanceIssues { get; init; }
    public required PerformanceIssue[] StringPerformanceIssues { get; init; }
    public required PerformanceMetrics Metrics { get; init; }
}

public record PerformanceIssue
{
    public required string Message { get; init; }
    public required int Line { get; init; }
    public required int Column { get; init; }
    public required string Category { get; init; }
    public required PerformanceSeverity Severity { get; init; }
    public required string Recommendation { get; init; }
    public required string? CodeSnippet { get; init; }
}

public record PerformanceMetrics
{
    public required int TotalPerformanceIssues { get; init; }
    public required int HighSeverityIssues { get; init; }
    public required int MediumSeverityIssues { get; init; }
    public required int LowSeverityIssues { get; init; }
    public required int LinqUsageCount { get; init; }
    public required int AsyncMethodCount { get; init; }
    public required int StringConcatenationCount { get; init; }
}

public enum PerformanceSeverity
{
    Low,
    Medium,
    High
}

namespace BuildValidator;

public record CommandLineOptions
{
    public string Directory { get; init; } = string.Empty;
    public int ParallelCount { get; init; } = Environment.ProcessorCount;
    public string Configuration { get; init; } = "Debug";
    public string Verbosity { get; init; } = "normal";
    public bool IncludeWarnings { get; init; } = false;
    public bool EnableAnalysis { get; init; } = false;
    public bool MetricsOnly { get; init; } = false;
    public bool IncludeMetrics { get; init; } = false;
    public int ComplexityThreshold { get; init; } = 10;
    public int MaintainabilityThreshold { get; init; } = 20;
    public string OutputFormat { get; init; } = "console";
    public string? OutputFile { get; init; } = null;
}

public static class CommandLineParser
{
    public static CommandLineOptions Parse(string[] args)
    {
        if (args.Length == 0)
        {
            ShowHelp();
            Environment.Exit(1);
        }

        // Check for help first
        if (args[0] == "--help" || args[0] == "-h")
        {
            ShowHelp();
            Environment.Exit(0);
        }

        var options = new CommandLineOptions
        {
            Directory = args[0], // First argument is always the directory
            ParallelCount = Environment.ProcessorCount,
            Configuration = "Debug",
            Verbosity = "normal",
            IncludeWarnings = false,
            EnableAnalysis = false,
            MetricsOnly = false,
            IncludeMetrics = false,
            ComplexityThreshold = 10,
            MaintainabilityThreshold = 20,
            OutputFormat = "console",
            OutputFile = null
        };

        // Parse remaining arguments
        for (int i = 1; i < args.Length; i++)
        {
            string arg = args[i];

            if (arg == "--parallel" || arg == "-p")
            {
                if (i + 1 < args.Length && int.TryParse(args[i + 1], out int parallel))
                {
                    options = options with { ParallelCount = parallel };
                    i++; // Skip the value
                }
                else
                {
                    Console.Error.WriteLine("Error: --parallel requires a numeric value");
                    Environment.Exit(1);
                }
            }
            else if (arg == "--config" || arg == "-c")
            {
                if (i + 1 < args.Length)
                {
                    string config = args[i + 1];
                    if (config.Equals("Debug", StringComparison.OrdinalIgnoreCase) || 
                        config.Equals("Release", StringComparison.OrdinalIgnoreCase))
                    {
                        options = options with { Configuration = config };
                        i++; // Skip the value
                    }
                    else
                    {
                        Console.Error.WriteLine("Error: Configuration must be either 'Debug' or 'Release'");
                        Environment.Exit(1);
                    }
                }
                else
                {
                    Console.Error.WriteLine("Error: --config requires a value");
                    Environment.Exit(1);
                }
            }
            else if (arg == "--verbosity" || arg == "-v")
            {
                if (i + 1 < args.Length)
                {
                    string verbosity = args[i + 1];
                    if (new[] { "minimal", "normal", "detailed" }.Contains(verbosity.ToLowerInvariant()))
                    {
                        options = options with { Verbosity = verbosity };
                        i++; // Skip the value
                    }
                    else
                    {
                        Console.Error.WriteLine("Error: Verbosity must be one of: minimal, normal, detailed");
                        Environment.Exit(1);
                    }
                }
                else
                {
                    Console.Error.WriteLine("Error: --verbosity requires a value");
                    Environment.Exit(1);
                }
            }
            else if (arg == "--warnings" || arg == "-w")
            {
                options = options with { IncludeWarnings = true };
            }
            else if (arg == "--analysis" || arg == "-a")
            {
                options = options with { EnableAnalysis = true };
            }
            else if (arg == "--metrics-only")
            {
                options = options with { MetricsOnly = true };
            }
            else if (arg == "--include-metrics")
            {
                options = options with { IncludeMetrics = true };
            }
            else if (arg == "--complexity-threshold")
            {
                if (i + 1 < args.Length && int.TryParse(args[i + 1], out int threshold))
                {
                    options = options with { ComplexityThreshold = threshold };
                    i++;
                }
                else
                {
                    Console.Error.WriteLine("Error: --complexity-threshold requires a numeric value");
                    Environment.Exit(1);
                }
            }
            else if (arg == "--maintainability-threshold")
            {
                if (i + 1 < args.Length && int.TryParse(args[i + 1], out int threshold))
                {
                    options = options with { MaintainabilityThreshold = threshold };
                    i++;
                }
                else
                {
                    Console.Error.WriteLine("Error: --maintainability-threshold requires a numeric value");
                    Environment.Exit(1);
                }
            }
            else if (arg == "--format")
            {
                if (i + 1 < args.Length)
                {
                    string format = args[i + 1];
                    if (new[] { "console", "json", "markdown", "md", "csv", "sarif" }.Contains(format.ToLowerInvariant()))
                    {
                        options = options with { OutputFormat = format };
                        i++;
                    }
                    else
                    {
                        Console.Error.WriteLine("Error: Format must be one of: console, json, markdown, md, csv, sarif");
                        Environment.Exit(1);
                    }
                }
                else
                {
                    Console.Error.WriteLine("Error: --format requires a value");
                    Environment.Exit(1);
                }
            }
            else if (arg == "--output")
            {
                if (i + 1 < args.Length)
                {
                    options = options with { OutputFile = args[i + 1] };
                    i++;
                }
                else
                {
                    Console.Error.WriteLine("Error: --output requires a file path");
                    Environment.Exit(1);
                }
            }
            else if (arg == "--help" || arg == "-h")
            {
                ShowHelp();
                Environment.Exit(0);
            }
            else
            {
                Console.Error.WriteLine($"Error: Unknown argument '{arg}'");
                Environment.Exit(1);
            }
        }

        // Validate directory exists
        if (!Directory.Exists(options.Directory))
        {
            Console.Error.WriteLine($"Error: Directory '{options.Directory}' does not exist");
            Environment.Exit(1);
        }

        // Validate parallel count
        if (options.ParallelCount <= 0)
        {
            Console.Error.WriteLine("Error: Parallel count must be greater than 0");
            Environment.Exit(1);
        }

        // Auto-detect format from file extension if output file is specified
        if (!string.IsNullOrEmpty(options.OutputFile) && options.OutputFormat == "console")
        {
            var extension = Path.GetExtension(options.OutputFile).ToLowerInvariant();
            var detectedFormat = extension switch
            {
                ".csv" => "csv",
                ".sarif" => "sarif", 
                ".json" => "json",
                ".md" => "markdown",
                ".markdown" => "markdown",
                _ => "console"
            };

            if (detectedFormat != "console")
            {
                options = options with { OutputFormat = detectedFormat };
                if (options.Verbosity != "minimal")
                {
                    Console.WriteLine($"Auto-detected format: {detectedFormat} from file extension");
                }
            }
        }

        return options;
    }

    private static void ShowHelp()
    {
        Console.WriteLine("BuildValidator - Validates C# projects using MSBuild compilation + advanced Roslyn analysis");
        Console.WriteLine();
        Console.WriteLine("Usage:");
        Console.WriteLine("  BuildValidator <directory> [options]");
        Console.WriteLine();
        Console.WriteLine("Arguments:");
        Console.WriteLine("  directory           The directory path to search for C# projects");
        Console.WriteLine();
